const useSearchProducts = (searchTerm) => {
  return useQuery({
    queryKey: ['products', 'search', searchTerm],
    queryFn: () => fetch(`/api/products?search=${searchTerm}`).then(res => res.json()),
    enabled: !!searchTerm, // La requête n'est exécutée que si searchTerm n'est pas vide
    staleTime: 1000 * 30 // 30 secondes
  });
};
```
L'option `enabled` empêche l'exécution de la requête lorsque le terme de recherche est vide, évitant ainsi des appels inutiles au backend.

